BEGIN TRANSACTION;

drop schema if exists "bollette_utenze" cascade;

create schema "bollette_utenze";
set search_path to "bollette_utenze";

CREATE TABLE PROVINCE (
    Sigla VARCHAR(10) PRIMARY KEY,
    NomeProvincia VARCHAR(255)
);

CREATE TABLE DISTRETTI (
    Prefisso VARCHAR(20) PRIMARY KEY,
    NomeDistretto VARCHAR(255),
    Provincia VARCHAR(10) REFERENCES PROVINCE(Sigla)
);

CREATE TABLE PERSONE (
    CodiceFiscale VARCHAR(16) PRIMARY KEY,
    Cognome VARCHAR(255),
    Nome VARCHAR(255),
    DataDiNascita DATE
);

CREATE TABLE UTENZE (
    Prefisso VARCHAR(20) REFERENCES DISTRETTI(Prefisso),
    Numero VARCHAR(20),
    Titolare VARCHAR(16) REFERENCES PERSONE(CodiceFiscale),
    Indirizzo VARCHAR(255),
    PRIMARY KEY (Prefisso, Numero)
);

CREATE TABLE BOLLETTE (
    CodiceBolletta VARCHAR(50) PRIMARY KEY,
    Prefisso VARCHAR(20),
    Numero VARCHAR(20),
    DataEmissione DATE,
    DataScadenza DATE,
    Importo DECIMAL(10,2),
    FOREIGN KEY (Prefisso, Numero) REFERENCES UTENZE(Prefisso, Numero)
);

CREATE TABLE PAGAMENTI (
    CodicePagamento VARCHAR(50) PRIMARY KEY,
    Bolletta VARCHAR(50) REFERENCES BOLLETTE(CodiceBolletta),
    Data DATE,
    Importo DECIMAL(10,2),
    Modalita VARCHAR(100)
);

-- No INSERT statements (exam PDF source, no data instances provided)

COMMIT;
